package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT;

        // Call the focal method
        CSVFormat result = format.withIgnoreEmptyLines();

        // Verify that the returned CSVFormat is a new instance and has ignoreEmptyLines = true
        assertNotNull(result);
        assertNotSame(format, result);
        assertTrue(result.getIgnoreEmptyLines());

        // Also verify original instance remains unchanged (DEFAULT has ignoreEmptyLines = false)
        assertFalse(format.getIgnoreEmptyLines());

        // Check that calling withIgnoreEmptyLines(false) returns new instance with false
        CSVFormat disabledIgnoreEmptyLines = format.withIgnoreEmptyLines(false);
        assertFalse(disabledIgnoreEmptyLines.getIgnoreEmptyLines());

        // Check that calling withIgnoreEmptyLines() on instance with ignoreEmptyLines=false returns new instance with true
        CSVFormat enabledIgnoreEmptyLines = disabledIgnoreEmptyLines.withIgnoreEmptyLines();
        assertTrue(enabledIgnoreEmptyLines.getIgnoreEmptyLines());
        assertNotSame(disabledIgnoreEmptyLines, enabledIgnoreEmptyLines);
    }
}
